import { useMutation } from '@tanstack/react-query';
import { useCallback, useContext, useEffect, useRef } from 'react';

import type { FilterSegment as QueryFilterSegment } from '@dynatrace-sdk/client-query';
import {
  addRecentSegmentsPreset,
  type UserSegmentsPresets,
} from '@dynatrace-sdk/segments-presets';

import { useStoreSelector } from '../../../core/store/selector.js';
import { isDev } from '../../../core/utils/is-node-environment.js';
import {
  handleFailedOptimisticMutation,
  handleSettledOptimisticMutation,
  runOptimisticMutation,
} from '../../helper/queryHelper.js';
import {
  useSegmentsCache,
  segmentsClient,
  type CachedSegment,
} from '../contexts/SegmentsCache/SegmentsCache.js';
import { SegmentsContext } from '../contexts/SegmentsStore/SegmentsContext.js';
import { UISegmentsDispatchContext } from '../contexts/SegmentsUI/SegmentsUIDispatchContext.js';
import { areUiSegmentsValid } from '../contexts/SegmentsUI/segmentValidationHelper.js';
import { isSelectedPreset } from '../parts/segmentsPresets/isSelectedPreset.js';

function updateCache(
  segments: QueryFilterSegment[],
  old?: UserSegmentsPresets,
): UserSegmentsPresets {
  if (!old) {
    return { recentPresets: [], pinnedPresets: [] };
  }

  const recentPresets = old.recentPresets;
  const recentPresetIndex = recentPresets.findIndex((preset) =>
    isSelectedPreset(segments, preset.segments),
  );

  if (recentPresetIndex > 0) {
    const oldPreset = old.recentPresets[recentPresetIndex];
    recentPresets.splice(recentPresetIndex, 1);
    recentPresets.unshift(oldPreset);
  }

  if (recentPresetIndex === -1) {
    const tempId = crypto.randomUUID();
    recentPresets.unshift({ id: tempId, segments });
    recentPresets.splice(10);
  }

  return {
    ...old,
    recentPresets,
  };
}

/**
 * @public
 * Provides the currently selected segments and helper functions to programmatically adjust the selection.
 *
 * @returns an object containing:
 * * segments - current selection of segments
 * * addSegment - function to add a segment to the selection
 * * removeSegment - function to remove a segment from the selection
 * * removeAllSegments - function to clear the selection
 * * setSegments - function to overwrite the current selection with a new one. If called with force=true, validation and permission checks are skipped
 */
export const useSegments = () => {
  const store = useContext(SegmentsContext);
  const storeRef = useRef(store);

  const segments = useStoreSelector<QueryFilterSegment[], QueryFilterSegment[]>(
    SegmentsContext,
    (state) => state,
  );
  const segmentsRef = useRef(segments);

  const { getSegment, getAllSegments } = useSegmentsCache();
  const { dispatch } = useContext(UISegmentsDispatchContext);
  const getAllSegmentsRef = useRef(getAllSegments);
  const getSegmentRef = useRef(getSegment);

  const { mutate: addToRecentPresetsMutationFn } = useMutation(
    {
      mutationKey: ['add-recent-segment-preset'],
      mutationFn: (segments: QueryFilterSegment[]) =>
        addRecentSegmentsPreset(segments),
      onMutate: async () =>
        runOptimisticMutation<UserSegmentsPresets>(
          'getSegmentsPresets',
          (prevState) => updateCache(segments, prevState),
        ),
      onError: (error, _, context) =>
        handleFailedOptimisticMutation('getSegmentsPresets', error, context),
      onSettled: () =>
        handleSettledOptimisticMutation(
          ['getSegmentsPresets'],
          ['add-recent-segment-preset'],
        ),
    },
    segmentsClient.queryClient,
  );

  useEffect(() => {
    segmentsRef.current = segments;
  }, [segments]);

  useEffect(() => {
    storeRef.current = store;
  }, [store]);

  useEffect(() => {
    getAllSegmentsRef.current = getAllSegments;
  }, [getAllSegments]);

  useEffect(() => {
    getSegmentRef.current = getSegment;
  }, [getSegment]);

  /**
   * Adds a segment to the store.
   * Validates segment before adding them.
   * @param segment - the segment to be added
   */
  const addSegment = useCallback(
    async (segment: QueryFilterSegment) => {
      const isAlreadyInStore = segmentsRef.current.find(
        (storeSegment) => storeSegment.id === segment.id,
      );

      if (isAlreadyInStore) {
        return false;
      }

      try {
        const safeSegment = await segmentsClient.queryClient.fetchQuery({
          queryKey: ['getSegment', segment.id],
          queryFn: () => getSegmentRef.current(segment.id),
        });
        if (safeSegment) {
          storeRef.current.setState((state) => {
            const newState = [...state];
            newState.push({ id: segment.id, variables: segment.variables });
            addToRecentPresetsMutationFn(newState);
            return newState;
          });
        }
      } catch (e) {
        if (isDev()) {
          // eslint-disable-next-line no-console
          console.warn(
            'SegmentSelector: The segment is not in the segments manager.',
            e,
          );
        }

        dispatch({ type: 'remove', payload: { id: segment.id } });
        return false;
      }
    },
    [dispatch, addToRecentPresetsMutationFn, getSegmentRef],
  );

  /**
   * Removes a segment from the store.
   * @param segment - the segment to be removed
   */
  const removeSegment = useCallback((id?: string | null) => {
    if (!id) {
      return;
    }

    storeRef.current.setState((state) =>
      state.filter((storeSegments) => id !== storeSegments.id),
    );
  }, []);

  /**
   * Removes all segments from the store.
   */
  const removeAllSegments = useCallback(
    () => storeRef.current.setState([]),
    [],
  );

  /**
   * Overwrites all segments with the provided segments array.
   * @param segments - new segments that should be applied
   * @param force - always apply segments ignoring validation and permissions
   */
  const setSegments = useCallback(
    async (segments: QueryFilterSegment[], force?: boolean) => {
      if (force) {
        storeRef.current.setState(segments);
        addToRecentPresetsMutationFn(segments);
        return;
      }

      // If the segments aren't in the cache, we need to fetch them.
      if (
        segmentsClient.queryClient.getQueryData<Map<string, CachedSegment>>([
          'getAllSegments',
        ]) === undefined
      ) {
        try {
          await segmentsClient.queryClient.fetchQuery({
            queryKey: ['getAllSegments'],
            queryFn: getAllSegmentsRef.current,
          });
        } catch (error) {
          if (isDev()) {
            // eslint-disable-next-line no-console
            console.warn(
              "SegmentSelector: Couldn't set segments due to a failed fetch.",
              error,
            );
          }

          if (segmentsClient.hasAccessRights) {
            // eslint-disable-next-line no-console
            console.error(
              "SegmentSelector: Couldn't set segments due to a failed fetch.",
              { cause: error },
            );
            return;
          }
        }
      }

      if (!segmentsClient.hasAccessRights) {
        storeRef.current.setState(segments);
        return;
      }

      const isValid = await areUiSegmentsValid(segments);

      if (!isValid) {
        // eslint-disable-next-line no-console
        console.error(
          "SegmentSelector: Couldn't set segments due to an invalid selection.",
        );
        return;
      }

      storeRef.current.setState(segments);
      addToRecentPresetsMutationFn(segments);
    },
    [addToRecentPresetsMutationFn],
  );

  return {
    segments,
    addSegment,
    removeSegment,
    removeAllSegments,
    setSegments,
  };
};
